import React from 'react';
import {View, Text, StyleSheet} from 'react-native';

export default function CalendarScreen({bills=[]}){
  // simple text list of upcoming bill due dates
  return (
    <View style={styles.screen}>
      <Text style={styles.title}>Calendar</Text>
      {bills.length > 0 ? (
        bills.map(b=> (
          <Text key={b.id} style={{marginTop:6}}>• {b.name} due on {b.due}th</Text>
        ))
      ) : (
        <Text style={{marginTop:8}}>No scheduled bills</Text>
      )}
      <Text style={{marginTop:12,color:'#666'}}>Tap a date to view events (demo)</Text>
    </View>
  );
}

const styles = StyleSheet.create({
  screen:{flex:1,padding:16},
  title:{fontSize:20,fontWeight:'700'}
});
